'use client';

import React, { useState } from 'react';
import Link from 'next/link';
import { Mail, Lock, ChevronRight, User, AlertCircle } from 'lucide-react';
import Button from '@/src/components/ui/Button';
import * as authService from '@/src/services/authService';
import { useAuth } from '@/src/context/AuthContext';
import { useRouter } from 'next/navigation';

export default function LoginPage() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const { setToken } = useAuth();
  const router = useRouter();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      const response = await authService.login(username, password);
      if (response.success && response.data?.token) {
        // Pass user data to context to avoid redundant /auth/me call
        const user = response.data.user;
        setToken(response.data.token, user);
        router.push('/dashboard');
      } else {
        setError(response.message || 'Đăng nhập thất bại. Vui lòng thử lại.');
      }
    } catch (err: any) {
      setError(err.message || 'Đăng nhập thất bại. Vui lòng thử lại.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white rounded-3xl shadow-2xl p-10 flex flex-col gap-8 relative overflow-hidden">
      {/* Login Header */}
      <div className="flex flex-col gap-2">
        <div className="w-12 h-12 bg-primary-soft rounded-xl flex items-center justify-center text-primary mb-4">
          <User className="w-6 h-6" />
        </div>
        <h2 className="text-3xl font-extrabold text-gray-900 tracking-tight">Đăng nhập</h2>
        <p className="text-gray-500 font-medium">Chào mừng bạn quay trở lại!</p>
      </div>

      {error && (
        <div className="bg-red-50 border border-red-100 text-red-600 px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-medium animate-in fade-in slide-in-from-top-2">
          <AlertCircle className="w-5 h-5 flex-shrink-0" />
          {error}
        </div>
      )}

      {/* Form Fields */}
      <form className="space-y-4" onSubmit={handleSubmit}>
        <div className="space-y-1.5 focus-within:z-10 relative">
          <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest pl-1">Tên đăng nhập</label>
          <div className="relative group">
            <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400 group-focus-within:text-primary transition-colors" />
            <input 
              type="text" 
              placeholder="admin" 
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              required
              className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-gray-100 rounded-2xl font-medium outline-none focus:border-primary/20 focus:bg-white transition-all text-gray-900"
            />
          </div>
        </div>

        <div className="space-y-1.5 relative">
          <div className="flex items-center justify-between pl-1">
            <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Mật khẩu</label>
            <Link href="#" className="text-[10px] font-bold text-primary uppercase tracking-widest hover:underline">Quên mật khẩu?</Link>
          </div>
          <div className="relative group">
            <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400 group-focus-within:text-primary transition-colors" />
            <input 
              type="password" 
              placeholder="••••••••" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-gray-100 rounded-2xl font-medium outline-none focus:border-primary/20 focus:bg-white transition-all text-gray-900"
            />
          </div>
        </div>

        <Button 
          fullWidth 
          size="lg" 
          type="submit"
          disabled={loading}
          className="rounded-2xl mt-6 py-4 flex items-center gap-2 group justify-center"
        >
          {loading ? 'Đang xử lý...' : (
            <>
              Tiếp tục <ChevronRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
            </>
          )}
        </Button>
      </form>

      {/* Footer */}
      <div className="text-center pt-4">
        <p className="text-sm text-gray-500 font-medium">
          Bạn chưa có tài khoản?{' '}
          <Link href="/register" className="text-primary font-bold hover:underline">Đăng ký ngay</Link>
        </p>
      </div>

      <div className="absolute top-0 right-0 w-32 h-32 bg-primary/5 rounded-full -mr-16 -mt-16"></div>
      <div className="absolute bottom-0 left-0 w-24 h-24 bg-primary/5 rounded-full -ml-12 -mb-12"></div>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import Link from 'next/link';
import { User, Phone, Mail, Lock, ChevronRight, GraduationCap, AlertCircle, Fingerprint } from 'lucide-react';
import Button from '@/src/components/ui/Button';
import * as authService from '@/src/services/authService';
import { useRouter } from 'next/navigation';

export default function RegisterPage() {
  const [fullName, setFullName] = useState('');
  const [username, setUsername] = useState('');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const router = useRouter();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    // Split Full Name into First and Last Name
    const nameParts = fullName.trim().split(' ');
    const first_name = nameParts.length > 1 ? nameParts.pop() || '' : nameParts[0];
    const last_name = nameParts.join(' ') || first_name;

    try {
      const response = await authService.register({
        username,
        password,
        first_name,
        last_name,
        email,
        phone,
      });

      if (response.success) {
        router.push('/login');
      } else {
        setError(response.message || 'Đăng ký thất bại. Vui lòng thử lại.');
      }
    } catch (err: any) {
      setError(err.message || 'Đăng ký thất bại. Vui lòng thử lại.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white rounded-3xl shadow-2xl p-10 flex flex-col gap-8 relative overflow-hidden">
      {/* Header Section */}
      <div className="flex flex-col gap-2">
        <div className="w-12 h-12 bg-primary-soft rounded-xl flex items-center justify-center text-primary mb-4">
          <GraduationCap className="w-6 h-6" />
        </div>
        <h2 className="text-3xl font-extrabold text-gray-900 tracking-tight">Đăng ký</h2>
        <p className="text-gray-500 font-medium">Bắt đầu hành trình của bạn ngay hôm nay!</p>
      </div>

      {error && (
        <div className="bg-red-50 border border-red-100 text-red-600 px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-medium animate-in fade-in slide-in-from-top-2">
          <AlertCircle className="w-5 h-5 flex-shrink-0" />
          {error}
        </div>
      )}

      {/* Form Section */}
      <form className="space-y-4" onSubmit={handleSubmit}>
        <div className="grid grid-cols-1 gap-4">
          <div className="space-y-1.5 relative group">
            <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest pl-1">Họ và tên</label>
            <div className="relative">
              <User className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400 group-focus-within:text-primary transition-colors" />
                <input 
                  type="text" 
                  placeholder="Nguyễn Văn An" 
                  value={fullName}
                  onChange={(e) => setFullName(e.target.value)}
                  required
                  className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-gray-100 rounded-2xl font-medium outline-none focus:border-primary/20 focus:bg-white transition-all text-gray-900"
                />
            </div>
          </div>

          <div className="space-y-1.5 relative group">
            <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest pl-1">Tên đăng nhập</label>
            <div className="relative">
              <Fingerprint className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400 group-focus-within:text-primary transition-colors" />
                <input 
                  type="text" 
                  placeholder="username123" 
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  required
                  className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-gray-100 rounded-2xl font-medium outline-none focus:border-primary/20 focus:bg-white transition-all text-gray-900"
                />
            </div>
          </div>

          <div className="space-y-1.5 relative group">
            <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest pl-1">Số điện thoại</label>
            <div className="relative">
              <Phone className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400 group-focus-within:text-primary transition-colors" />
                <input 
                  type="tel" 
                  placeholder="0912 345 678" 
                  value={phone}
                  onChange={(e) => setPhone(e.target.value)}
                  required
                  className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-gray-100 rounded-2xl font-medium outline-none focus:border-primary/20 focus:bg-white transition-all text-gray-900"
                />
            </div>
          </div>

          <div className="space-y-1.5 relative group">
            <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest pl-1">Email liên lạc</label>
            <div className="relative">
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400 group-focus-within:text-primary transition-colors" />
                <input 
                  type="email" 
                  placeholder="an.nguyenv@gmail.com" 
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-gray-100 rounded-2xl font-medium outline-none focus:border-primary/20 focus:bg-white transition-all text-gray-900"
                />
            </div>
          </div>

          <div className="space-y-1.5 relative group">
            <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest pl-1">Mật khẩu</label>
            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400 group-focus-within:text-primary transition-colors" />
                <input 
                  type="password" 
                  placeholder="••••••••" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                  className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-gray-100 rounded-2xl font-medium outline-none focus:border-primary/20 focus:bg-white transition-all text-gray-900"
                />
            </div>
          </div>
        </div>

        <Button 
          fullWidth 
          size="lg" 
          type="submit"
          disabled={loading}
          className="rounded-2xl mt-6 py-4 flex items-center gap-2 group justify-center"
        >
          {loading ? 'Đang tạo tài khoản...' : (
            <>
              Tạo tài khoản <ChevronRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
            </>
          )}
        </Button>
      </form>

      {/* Footer */}
      <div className="text-center pt-4">
        <p className="text-sm text-gray-500 font-medium">
          Đã có tài khoản?{' '}
          <Link href="/login" className="text-primary font-bold hover:underline">Đăng nhập ngay</Link>
        </p>
      </div>

      <div className="absolute top-0 right-0 w-32 h-32 bg-primary/5 rounded-full -mr-16 -mt-16"></div>
      <div className="absolute bottom-0 left-0 w-24 h-24 bg-primary/5 rounded-full -ml-12 -mb-12"></div>
    </div>
  );
}

